1	'use strict';
2	// 간단한 LCS(최장 공통 부분수열) 기반 라인 diff. 외부 의존성 없이, 가독성 우선.
3	// canonical 본문과 배포본 본문을 줄 단위로 비교해 +/-/(공백)으로 표시한다.
4	
5	function lineDiff(oldText, newText) {
6	  const a = oldText.split('\n');
7	  const b = newText.split('\n');
8	  const m = a.length;
9	  const n = b.length;
10	
11	  // dp[i][j] = a[i..], b[j..]의 LCS 길이
12	  const dp = Array.from({ length: m + 1 }, () => new Array(n + 1).fill(0));
13	  for (let i = m - 1; i >= 0; i--) {
14	    for (let j = n - 1; j >= 0; j--) {
15	      dp[i][j] = a[i] === b[j] ? dp[i + 1][j + 1] + 1 : Math.max(dp[i + 1][j], dp[i][j + 1]);
16	    }
17	  }
18	
19	  const out = [];
20	  let i = 0;
21	  let j = 0;
22	  while (i < m && j < n) {
23	    if (a[i] === b[j]) {
24	      out.push({ type: ' ', line: a[i] });
25	      i++;
26	      j++;
27	    } else if (dp[i + 1][j] >= dp[i][j + 1]) {
28	      out.push({ type: '-', line: a[i] }); // 배포본에서 사라질 줄
29	      i++;
30	    } else {
31	      out.push({ type: '+', line: b[j] }); // 새로 들어갈 줄
32	      j++;
33	    }
34	  }
35	  while (i < m) out.push({ type: '-', line: a[i++] });
36	  while (j < n) out.push({ type: '+', line: b[j++] });
37	  return out;
38	}
39	
40	function hasChanges(diff) {
41	  return diff.some((d) => d.type !== ' ');
42	}
43	
44	// 터미널/엔드포인트 출력용 텍스트 ("+ ...", "- ...", "  ...")
45	function render(diff) {
46	  return diff.map((d) => `${d.type} ${d.line}`).join('\n');
47	}
48	
49	// lineDiff 결과를 hunk 단위로 그룹화한다.
50	// 변경(+/-) 주변 context줄의 미변경( )만 남기고, 그보다 긴 미변경 구간은 접는다.
51	// 반환: [{ lines: [{type,line}], hiddenBefore: number }]
52	//   - lines       : 이 hunk에 포함되는 줄들(변경줄 + 양옆 문맥줄)
53	//   - hiddenBefore : 이 hunk 앞에서 접혀 생략된 미변경 줄 수
54	//                    (첫 hunk면 파일 맨 앞에서 생략된 줄 수)
55	// 동작 메모:
56	//   - 변경이 전혀 없으면 빈 배열([])을 반환한다(접을 hunk가 없으므로).
57	//   - 마지막 hunk 뒤에 남는 미변경 구간(꼬리)은 표시 대상이 아니므로 무시한다
58	//     (어느 hunk에도 hiddenAfter로 싣지 않는다 — renderHunked도 꼬리는 그리지 않음).
59	function hunks(diff, context = 3) {
60	  // 변경이 없으면 hunk도 없다.
61	  if (!hasChanges(diff)) return [];
62	
63	  // 1) 각 줄을 hunk에 "포함할지" 마킹한다.
64	  //    - 변경줄(+/-)은 무조건 포함.
65	  //    - 변경줄에서 앞뒤로 context 거리 이내의 미변경줄도 포함(문맥).
66	  const keep = new Array(diff.length).fill(false);
67	  for (let idx = 0; idx < diff.length; idx++) {
68	    if (diff[idx].type === ' ') continue;
69	    const from = Math.max(0, idx - context);
70	    const to = Math.min(diff.length - 1, idx + context);
71	    for (let k = from; k <= to; k++) keep[k] = true;
72	  }
73	
74	  // 2) keep 구간을 이어붙여 hunk로 묶고, 그 사이 접힌 미변경 줄 수를 센다.
75	  const result = [];
76	  let hiddenRun = 0; // 직전 hunk 이후(또는 파일 시작 이후) 접힌 미변경 줄 수 누적
77	  let current = null; // 현재 만들고 있는 hunk
78	
79	  for (let idx = 0; idx < diff.length; idx++) {
80	    if (keep[idx]) {
81	      if (!current) {
82	        // 새 hunk 시작 — 지금까지 접힌 줄 수를 hiddenBefore로 싣는다.
83	        current = { lines: [], hiddenBefore: hiddenRun };
84	        result.push(current);
85	        hiddenRun = 0;
86	      }
87	      current.lines.push(diff[idx]);
88	    } else {
89	      // keep 안 되는 줄은 정의상 미변경줄이므로 접힘으로 카운트.
90	      hiddenRun++;
91	      current = null; // hunk 경계
92	    }
93	  }
94	
95	  // 꼬리(hiddenRun > 0)는 위 동작 메모대로 무시한다.
96	  return result;
97	}
98	
99	// hunk 렌더러(텍스트). hunk 내부는 render와 동일한 "+ /- /  " 접두사,
100	// hunk 사이의 접힌 구간은 "  ⋯ (N줄 변경 없음)" 구분선으로 표시한다.
101	function renderHunked(diff, context = 3) {
102	  const hs = hunks(diff, context);
103	  const parts = [];
104	  for (const h of hs) {
105	    if (h.hiddenBefore > 0) {
106	      parts.push(`  ⋯ (${h.hiddenBefore}줄 변경 없음)`);
107	    }
108	    for (const d of h.lines) {
109	      parts.push(`${d.type} ${d.line}`);
110	    }
111	  }
112	  return parts.join('\n');
113	}
114	
115	module.exports = { lineDiff, hasChanges, render, hunks, renderHunked };
