118	if (require.main === module) {
119	  // 여러 줄 중 일부만 변경된 예시: 긴 미변경 구간이 hunk 사이에서 접히는지 확인.
120	  const a = [
121	    'line 1',
122	    'line 2',
123	    'line 3',
124	    'line 4',
125	    'line 5',
126	    'line 6',
127	    'line 7',
128	    'line 8',
129	    'line 9',
130	    'line 10',
131	    'line 11',
132	    'line 12',
133	  ].join('\n');
134	
135	  const b = [
136	    'line 1 CHANGED',
137	    'line 2',
138	    'line 3',
139	    'line 4',
140	    'line 5',
141	    'line 6',
142	    'line 7',
143	    'line 8',
144	    'line 9',
145	    'line 10',
146	    'line 11 CHANGED',
147	    'line 12',
148	  ].join('\n');
149	
150	  const d = lineDiff(a, b);
151	  console.log('--- render(전체) ---');
152	  console.log(render(d));
153	  console.log('--- renderHunked(문맥3) ---');
154	  console.log(renderHunked(d));
155	}
