1	'use strict';
2	// 얇은 로컬 서버 (다리). 127.0.0.1에만 바인딩하고, 엔드포인트는 cli/core를 호출만 한다.
3	// 로직 중복 없음 — 모든 동작은 core에 있다.
4	
5	const http = require('http');
6	const fs = require('fs');
7	const path = require('path');
8	const core = require('../cli/core');
9	const mode = require('../cli/mode');
10	const paths = require('../cli/paths');
11	
12	const DASHBOARD_DIR = path.join(__dirname, '..', 'dashboard');
13	
14	function sendJson(res, code, obj) {
15	  const body = JSON.stringify(obj);
16	  res.writeHead(code, { 'Content-Type': 'application/json; charset=utf-8' });
17	  res.end(body);
18	}
19	
20	function sendFile(res, file, type) {
21	  fs.readFile(file, (err, data) => {
22	    if (err) {
23	      res.writeHead(404);
24	      res.end('not found');
25	      return;
26	    }
27	    res.writeHead(200, { 'Content-Type': type });
28	    res.end(data);
29	  });
30	}
31	
32	function readBody(req) {
33	  return new Promise((resolve) => {
34	    let data = '';
35	    req.on('data', (c) => (data += c));
36	    req.on('end', () => {
37	      try {
38	        resolve(data ? JSON.parse(data) : {});
39	      } catch {
40	        resolve({});
41	      }
42	    });
43	  });
44	}
45	
46	function start({ port = 4319 } = {}) {
47	  const server = http.createServer(async (req, res) => {
48	    const url = new URL(req.url, 'http://127.0.0.1');
49	    const route = url.pathname;
50	    try {
51	      // --- 정적 파일 ---
52	      if (req.method === 'GET' && route === '/') {
53	        return sendFile(res, path.join(DASHBOARD_DIR, 'index.html'), 'text/html; charset=utf-8');
54	      }
55	      if (req.method === 'GET' && route === '/app.js') {
56	        return sendFile(res, path.join(DASHBOARD_DIR, 'app.js'), 'text/javascript; charset=utf-8');
57	      }
58	      if (req.method === 'GET' && route === '/design-system.css') {
59	        return sendFile(res, path.join(DASHBOARD_DIR, 'design-system.css'), 'text/css; charset=utf-8');
60	      }
61	
62	      // --- 데이터 소스 모드 (실제/더미 토글) ---
63	      if (req.method === 'GET' && route === '/mode') {
64	        // 경로만 돌려준다(파일 내용 아님). UI가 "어디서 읽는지"·"실제 모드 잠김 여부" 표시용.
65	        return sendJson(res, 200, {
66	          mode: mode.getMode(),
67	          realAllowed: mode.realAllowed(), // AAD_ALLOW_REAL=1 옵트인 여부
68	          canonicalPath: paths.canonicalRoot(),
69	          homes: paths.toolHomes(),
70	        });
71	      }
72	      if (req.method === 'POST' && route === '/mode') {
73	        const b = await readBody(req);
74	        const applied = mode.setMode(b.mode);
75	        // real을 요청했는데 dummy로 남았으면 옵트인이 없어 차단된 것.
76	        const blocked = b.mode === 'real' && applied !== 'real';
77	        return sendJson(res, 200, { mode: applied, realAllowed: mode.realAllowed(), blocked });
78	      }
79	
80	      // --- API (core 호출) ---
81	      if (req.method === 'GET' && route === '/overview') {
82	        return sendJson(res, 200, core.overview()); // 하이브리드: 존재만
83	      }
84	      if (req.method === 'GET' && route === '/diff') {
85	        return sendJson(res, 200, core.diffFor(url.searchParams.get('to'))); // 클릭 시 drift
86	      }
87	      if (req.method === 'POST' && route === '/pull') {
88	        const b = await readBody(req);
89	        try {
90	          return sendJson(res, 200, core.pull({ from: b.from, piAck: b.piAck }));
91	        } catch (e) {
92	          if (e instanceof core.PiGateError) {
93	            // PI 게이트: 409 + 감지 내용 → 프런트가 확인 모달을 띄운다
94	            return sendJson(res, 409, { piGate: true, detected: e.detected, maskedLines: e.maskedLines });
95	          }
96	          throw e;
97	        }
98	      }
99	      if (req.method === 'POST' && route === '/push') {
100	        const b = await readBody(req);
101	        return sendJson(res, 200, core.push({ to: b.to, apply: !!b.apply }));
102	      }
103	
104	      // --- 프로젝트 레지스트리 API (T2, core 호출만) ---
105	      if (req.method === 'GET' && route === '/projects') {
106	        return sendJson(res, 200, core.projectsList()); // 등록 목록
107	      }
108	      if (req.method === 'POST' && route === '/projects/scan') {
109	        const b = await readBody(req);
110	        return sendJson(res, 200, core.projectsScan({ root: b.root })); // 후보만 — 등록 안 함
111	      }
112	      if (req.method === 'POST' && route === '/projects/adopt') {
113	        const b = await readBody(req);
114	        return sendJson(res, 200, core.projectsAdopt({ candidates: b.candidates }));
115	      }
116	      if (req.method === 'POST' && route === '/projects/add') {
117	        const b = await readBody(req);
118	        return sendJson(res, 200, core.projectsAdd({ root: b.root }));
119	      }
120	      if (req.method === 'POST' && route === '/projects/remove') {
121	        const b = await readBody(req);
122	        return sendJson(res, 200, core.projectsRemove({ root: b.root }));
123	      }
124	
125	      // --- agent 트랙 API (지시문 트랙과 동일 패턴, core 호출만) ---
126	      if (req.method === 'GET' && route === '/agents/overview') {
127	        return sendJson(res, 200, core.agentOverview()); // canonical agents + 도구별 발견 + 비표준
128	      }
129	      if (req.method === 'GET' && route === '/agents/diff') {
130	        // 미리보기: canonical agent → 특정 도구 렌더 결과(diff + 손실)
131	        return sendJson(res, 200, core.agentDiff(url.searchParams.get('id'), url.searchParams.get('to')));
132	      }
133	      if (req.method === 'POST' && route === '/agents/pull') {
134	        const b = await readBody(req);
135	        try {
136	          return sendJson(res, 200, core.agentPull({ from: b.from, name: b.name, piAck: b.piAck, projectRoot: b.projectRoot }));
137	        } catch (e) {
138	          if (e instanceof core.PiGateError) {
139	            // PI 게이트: 409 + 감지 내용 → 프런트가 확인 모달을 띄운다
140	            return sendJson(res, 409, { piGate: true, detected: e.detected, maskedLines: e.maskedLines });
141	          }
142	          throw e;
143	        }
144	      }
145	      if (req.method === 'POST' && route === '/agents/push') {
146	        const b = await readBody(req);
147	        return sendJson(res, 200, core.agentPush({ id: b.id, to: b.to, apply: !!b.apply }));
148	      }
149	
150	      // --- skill 트랙 API (동일 패턴, core 호출만) ---
151	      if (req.method === 'GET' && route === '/skills/overview') {
152	        return sendJson(res, 200, core.skillOverview()); // canonical + 도구별 발견 + 비공식
153	      }
154	      if (req.method === 'GET' && route === '/skills/diff') {
155	        return sendJson(res, 200, core.skillDiff(url.searchParams.get('name'), url.searchParams.get('to')));
156	      }
157	      if (req.method === 'POST' && route === '/skills/pull') {
158	        const b = await readBody(req);
159	        try {
160	          return sendJson(res, 200, core.skillPull({ name: b.name, source_id: b.source_id, piAck: b.piAck, projectRoot: b.projectRoot }));
161	        } catch (e) {
162	          if (e instanceof core.PiGateError) {
163	            return sendJson(res, 409, { piGate: true, detected: e.detected, maskedLines: e.maskedLines });
164	          }
165	          throw e;
166	        }
167	      }
168	      if (req.method === 'POST' && route === '/skills/push') {
169	        const b = await readBody(req);
170	        return sendJson(res, 200, core.skillPush({ name: b.name, to: b.to, apply: !!b.apply }));
171	      }
172	
173	      // --- 한 번에 동기화(Sync) API (UX-A, core 호출만) ---
174	      if (req.method === 'GET' && route === '/sync/plan') {
175	        // 읽기 전용 계획: 도구별 그룹/특이사항/기준 후보/기준별 손실
176	        return sendJson(res, 200, core.syncPlan({ kind: url.searchParams.get('kind'), name: url.searchParams.get('name') }));
177	      }
178	      if (req.method === 'POST' && route === '/sync/apply') {
179	        const b = await readBody(req);
180	        try {
181	          // pull(기준→canonical) + push(나머지 도구). PI는 기존 pull과 동일하게 409.
182	          return sendJson(res, 200, core.syncApply({ kind: b.kind, name: b.name, baseTool: b.baseTool, sourceId: b.sourceId, piAck: b.piAck }));
183	        } catch (e) {
184	          if (e instanceof core.PiGateError) {
185	            return sendJson(res, 409, { piGate: true, detected: e.detected, maskedLines: e.maskedLines });
186	          }
187	          throw e;
188	        }
189	      }
190	
191	      // --- 동기화 매트릭스 API (UX-E1, core 호출만) ---
192	      if (req.method === 'GET' && route === '/matrix') {
193	        // 행=(scope,name) × 도구 슬롯 + 동기화 상태. 첫 호출 시 프로젝트 자동 발견(레지스트리 비었을 때만).
194	        return sendJson(res, 200, core.syncMatrix({ kind: url.searchParams.get('kind') }));
195	      }
196	
197	      // --- 스킬/에이전트 본문 뷰어 (이슈5, core 호출만) ---
198	      if (req.method === 'GET' && route === '/item/content') {
199	        try {
200	          return sendJson(res, 200, core.itemContent({
201	            kind: url.searchParams.get('kind'),
202	            name: url.searchParams.get('name'),
203	            scope: url.searchParams.get('scope') || undefined,
204	            tool: url.searchParams.get('tool') || undefined,
205	            piAck: url.searchParams.get('piAck') || undefined,
206	          }));
207	        } catch (e) {
208	          if (e instanceof core.PiGateError) {
209	            // PI 게이트: 409 + 감지 내용 → 프런트가 PI 모달(마스킹 후 보기/취소)을 띄운다.
210	            return sendJson(res, 409, { piGate: true, detected: e.detected, maskedLines: e.maskedLines });
211	          }
212	          throw e;
213	        }
214	      }
215	
216	      // --- 지시문 매트릭스 / 한 방 동기화 API (UX v2 — F2, core 호출만) ---
217	      if (req.method === 'GET' && route === '/instr/matrix') {
218	        // 전역 지시문 3파일 비교(존재/내용그룹/종합상태). canonical은 계산에 넣지 않음(순수 백업).
219	        return sendJson(res, 200, core.instrMatrix());
220	      }
221	      if (req.method === 'POST' && route === '/instr/sync') {
222	        const b = await readBody(req);
223	        try {
224	          // apply:false=diff 요약(디스크 무변경), apply:true=pull(base)→push. PI는 기존 pull과 동일 409.
225	          return sendJson(res, 200, core.instrSync({ base: b.base, apply: !!b.apply, piAck: b.piAck }));
226	        } catch (e) {
227	          if (e instanceof core.PiGateError) {
228	            return sendJson(res, 409, { piGate: true, detected: e.detected, maskedLines: e.maskedLines });
229	          }
230	          throw e;
231	        }
232	      }
233	
234	      // --- 백업 목록 / 복구 API (UX-D1, core 호출만) ---
235	      if (req.method === 'GET' && route === '/backups') {
236	        return sendJson(res, 200, core.backupsList()); // 최신순 백업 목록(원위치 정보 포함)
237	      }
238	      if (req.method === 'POST' && route === '/backups/restore') {
239	        const b = await readBody(req);
240	        // 복구: backup.js가 경로 탈출 차단 + 대상 화이트리스트 검증을 강제한다.
241	        // 거부(경로 밖·비정당 대상)는 아래 공통 catch가 500 {error}로 표면화.
242	        return sendJson(res, 200, core.backupRestore({ path: b.path }));
243	      }
244	
245	      // --- 태그 + 스토어(카탈로그) API (core 호출만) ---
246	      if (req.method === 'GET' && route === '/tags') {
247	        return sendJson(res, 200, core.tagSuggestions());
248	      }
249	      if (req.method === 'POST' && route === '/tags/set') {
250	        const b = await readBody(req);
251	        return sendJson(res, 200, core.setItemTags(b));
252	      }
253	      if (req.method === 'GET' && route === '/store') {
254	        // SKC1: ?publisher=<slug> 로 퍼블리셔 필터(있으면 core.storeList에 전달). ?q= 유지.
255	        return sendJson(res, 200, core.storeList(
256	          url.searchParams.get('q') || undefined,
257	          { publisher: url.searchParams.get('publisher') || undefined }
258	        ));
